// n8n Code node (после RabbitMQ Trigger)
// Формирует ровный payload для Odoo crm.lead
// Возвращает для каждого входного item:
// { name, contact_name, email_from, phone, description, type }

function s(x) { return (x ?? '').toString().trim(); }

const outputs = items.map(item => {
  // raw — то, что вернул RabbitMQ Trigger в item.json
  const raw = item.json ?? {};

  // возможные места, где лежат данные
  // 1) raw.content (часто строка JSON)
  // 2) raw.body (объект)
  // 3) raw.message / raw.payload
  // 4) сам raw
  let content = raw.content ?? raw.body ?? raw.message ?? raw.payload ?? raw;

  // если content — строка, пытаемся распарсить как JSON
  if (typeof content === 'string') {
    try {
      content = JSON.parse(content);
    } catch (e) {
      // Если парсинг не удался — оставляем строку и постараемся извлечь поля простым поиском
      // (на случай, если content = "name=...&phone=..." или подобное)
      // В большинстве случаев это не потребуется.
      content = { rawString: content };
    }
  }

  // Иногда полезная нагрузка может оказаться вложенной: content.body
  if (content && typeof content === 'object' && (content.body && typeof content.body === 'object')) {
    content = content.body;
  }

  // стандартные варианты имён полей
  const firstname = s(content.firstname ?? content.firstName ?? content.first_name ?? '');
  const lastname  = s(content.lastname  ?? content.lastName  ?? content.last_name  ?? '');
  const nameFromFields = `${firstname} ${lastname}`.trim();

  const name         = s(content.name ?? content.contact_name ?? nameFromFields ?? content.title ?? '');
  const contact_name = s(content.contact_name ?? content.contactName ?? name);
  const email_from   = s(content.email_from ?? content.email ?? content.emailAddress ?? '');
  const phone        = s(content.phone ?? content.mobile ?? content.phoneNumber ?? '');
  const description  = s(content.description ?? content.notes ?? content.comment ?? '');
  const type         = s(content.type ?? 'lead');

  // final: гарантируем, что name не пустой
  const finalName = name || contact_name || email_from || 'New Lead';

  return {
    json: {
      name: finalName,
      contact_name: contact_name || finalName,
      email_from,
      phone,
      description,
      type
    }
  };
});

return outputs;
